<?php
session_start(); require 'db_connection.php'; require_once 'helpers.php'; require_login(); $conn=OpenCon(); $orderId=(int)($_GET['order_id']??0);
$sql="SELECT o.id,o.user_id,o.total_price,o.order_type,o.order_status,u.first_name,u.email FROM orders o JOIN users u ON u.id=o.user_id WHERE o.id=?"; $stmt=$conn->prepare($sql); $stmt->bind_param("i",$orderId); $stmt->execute(); $order=$stmt->get_result()->fetch_assoc(); if(!$order) die('Invalid order');
if(!is_admin() && (int)$order['user_id']!==current_user_id()) die('Access Denied');
$status=$order['order_status']?:'processing'; $c=$conn->prepare("SELECT status FROM closed_orders WHERE order_id=?"); $c->bind_param("i",$orderId); $c->execute(); if($c->get_result()->num_rows>0) $status='completed';
$items=$conn->prepare("SELECT p.name,oi.quantity,p.price FROM order_items oi JOIN products p ON p.id=oi.product_id WHERE oi.order_id=?"); $items->bind_param("i",$orderId); $items->execute(); $res=$items->get_result();
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Order Details</title><link rel="stylesheet" href="css/style.css"></head><body><?php include 'navbar.php'; ?><div class="container"><h2>Order #<?=$orderId?> Details</h2><div class="card"><p><b>User:</b> <?=e($order['first_name'])?></p><p><b>Email:</b> <?=e($order['email'])?></p><p><b>Order Type:</b> <?=e(strtoupper($order['order_type']))?></p><p><b>Status:</b> <span class="badge <?=e($status)?>"><?=e(ucfirst($status))?></span></p></div><br><table><tr><th>Product</th><th>Qty</th><th>Price</th><th>Total</th></tr><?php while($i=$res->fetch_assoc()):?><tr><td><?=e($i['name'])?></td><td><?=(int)$i['quantity']?></td><td>$<?=number_format((float)$i['price'],2)?></td><td>$<?=number_format((int)$i['quantity']*(float)$i['price'],2)?></td></tr><?php endwhile;?></table><h3>Total: $<?=number_format((float)$order['total_price'],2)?></h3></div></body></html>
